Here's a complete example using modern MSTest (v3+) patterns:

```csharp
[TestClass]
public class DataFetcherTests
{
    // MSTest v3 injects TestContext with a CancellationToken
    // that is automatically cancelled when [Timeout] expires.
    public TestContext TestContext { get; set; } = null!;

    // --- Helper: fake handler to avoid real HTTP calls ---
    private static HttpClient CreateMockClient(
        HttpStatusCode status, string content)
    {
        var handler = new MockHandler(status, content);
        return new HttpClient(handler);
    }

    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _status;
        private readonly string _content;

        public MockHandler(HttpStatusCode status, string content)
        {
            _status = status;
            _content = content;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(_status)
            {
                Content = new StringContent(_content)
            };
            return Task.FromResult(response);
        }
    }

    // 1) Basic async success test
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // 2) Verify non-success status codes throw
    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        using var client = CreateMockClient(
            HttpStatusCode.InternalServerError, "");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // 3) Timeout — MSTest cancels TestContext.CancellationTokenSource
    //    automatically when the timeout expires.
    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_RespectsTimeout()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);

        // Pass the framework-managed token so the test is
        // cancelled cleanly if it exceeds 1 second.
        var token = TestContext.CancellationTokenSource.Token;
        var result = await fetcher.FetchAsync("https://example.com", token);

        Assert.AreEqual("data", result);
    }

    // 4) Explicit cancellation — prove the method stops early
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<OperationCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }
}
```

**Key patterns:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task`, never `async void` |
| **Timeouts** | `[Timeout(ms)]` + pass `TestContext.CancellationTokenSource.Token` into the code under test |
| **Cancellation** | Pre-cancel a `CancellationTokenSource` and assert `OperationCanceledException` |
| **Mock HTTP** | Custom `HttpMessageHandler` — avoids needing Moq for `HttpClient` |

The critical MSTest v3 detail: `TestContext.CancellationTokenSource.Token` is the **same token** the framework cancels when `[Timeout]` fires, so wiring it through gives you cooperative cancellation for free.
